insert into public.faq_entries (id, question, answer, category, sort_order, is_active) values ('09bfb5f3-40c8-58fa-88c0-0763f014deab', 'How is this different from a habit tracker or generic coaching app?', 'Most apps reset to zero context every session. Executive Coach AI builds a persistent behavioral model of you over months — tracking your task completion patterns, emotional triggers, and avoidance cycles. Your weekly retrospectives are generated from your actual history, so the coaching quality compounds the longer you stay.', 'Getting Started', 1, true) on conflict (id) do nothing;
insert into public.faq_entries (id, question, answer, category, sort_order, is_active) values ('e9e0784a-3a00-5f74-84d3-9b6a2a0b1369', 'Is this built specifically for people with ADHD?', 'Yes. It''s designed for high-earning professionals with ADHD who struggle with avoidance cycles and follow-through but can''t justify the time or cost of a human executive coach. The real-time drift nudges are tuned to catch the moments where ADHD brains tend to derail.', 'Getting Started', 2, true) on conflict (id) do nothing;
insert into public.faq_entries (id, question, answer, category, sort_order, is_active) values ('d320225d-4a90-5fee-8c76-7ff45e7fe6f5', 'What exactly is a weekly retrospective?', 'Each week the coach reviews your logged tasks, completion rates, and emotional check-ins, then generates a structured summary: what you finished, where you drifted, which triggers showed up, and one or two concrete adjustments for the week ahead. It reads like a coach who actually remembers your last three months.', 'Features', 3, true) on conflict (id) do nothing;
insert into public.faq_entries (id, question, answer, category, sort_order, is_active) values ('952b9cb7-9155-59e9-8594-5ea61cb7c782', 'How do real-time drift nudges work?', 'The app watches for patterns it has learned signal avoidance — stalled tasks, skipped check-ins, or activity at times you historically procrastinate. When it detects drift, it sends a short, context-aware nudge to pull you back before the cycle compounds.', 'Features', 4, true) on conflict (id) do nothing;
insert into public.faq_entries (id, question, answer, category, sort_order, is_active) values ('89fee4e4-1777-5255-83b8-f1ed55216b1f', 'What happens to my behavioral data and is it private?', 'Your behavioral history is yours and is stored securely. It''s used only to power your coaching model and is never sold. You can export or delete your data at any time, though deleting it resets the compounding context the coach relies on.', 'Privacy & Data', 5, true) on conflict (id) do nothing;
insert into public.faq_entries (id, question, answer, category, sort_order, is_active) values ('a0125c90-e72f-5454-8b02-8b4eabaa83d9', 'How much does it cost?', 'Executive Coach AI is a fraction of the cost of a human executive coach, who typically runs hundreds of dollars per session. It''s offered as a monthly or annual subscription, with the annual plan giving the best value for users committed to long-term behavioral change.', 'Billing', 6, true) on conflict (id) do nothing;
